import { AxisScale, SharedAxisProps } from '@visx/axis';
import type { SVGAttributes } from 'react';

import { TextProps } from '../../types/text-props.js';

/**
 * @internal
 */
export type Orientation = 'left' | 'right' | 'bottom' | 'top';

/**
 * @public
 */
export const HORIZONTAL_LABEL_LAYOUT_TYPE = 'horizontal';
/**
 * @public
 */
export const VERTICAL_LABEL_LAYOUT_TYPE = 'vertical';

/** Defines the options for displaying the tick labels in an axis
 * @public
 */
export type TickLabelLayout =
  | typeof HORIZONTAL_LABEL_LAYOUT_TYPE
  | typeof VERTICAL_LABEL_LAYOUT_TYPE;

/**
 * @internal
 */
export interface AxisProps extends SharedAxisProps<AxisScale> {
  width?: SVGAttributes<SVGSVGElement>['width'];
  height?: SVGAttributes<SVGSVGElement>['height'];
  containerSize: number;
  stroke?: string;
  size?: 'small' | 'base';
  tickColor?: string;
  role?: string;
  ['aria-label']?: string;
}

/**
 * @internal
 */
export type OrientedAxisProps = Omit<
  AxisProps,
  'orientation' | 'width' | 'height'
> & {
  width?: number;
  height?: number;
};

/**
 * @internal
 */
export type TextPropsRequired = Required<
  Pick<TextProps, 'fill' | 'fontFamily'>
> & {
  fontSize: string;
  color: string;
};

/**
 * record of category id and category name
 * @internal
 */
export type TickCategory = Record<string, string>;
